import { randomUUID } from 'node:crypto';
import { McpServer } from '@modelcontextprotocol/server';
import { NodeStreamableHTTPServerTransport } from '@modelcontextprotocol/node';
import { createMcpExpressApp } from '@modelcontextprotocol/express';
import * as z from 'zod/v4';

const server = new McpServer({ name: 'my-server', version: '1.0.0' });

server.registerTool(
  'calculate-bmi',
  {
    title: 'BMI Calculator',
    description: 'Calculate Body Mass Index',
    inputSchema: z.object({ weightKg: z.number(), heightM: z.number() }),
    outputSchema: z.object({ bmi: z.number() }),
    annotations: { destructiveHint: false, idempotentHint: true }
  },
  async ({ weightKg, heightM }) => {
    const bmi = weightKg / (heightM * heightM);
    return {
      content: [{ type: 'text', text: JSON.stringify({ bmi }) }],
      structuredContent: { bmi }
    };
  }
);

const app = createMcpExpressApp();
const transport = new NodeStreamableHTTPServerTransport({
  sessionIdGenerator: () => randomUUID()
});
await server.connect(transport);
app.all('/mcp', async (req, res) => await transport.handleRequest(req, res, req.body));
app.listen(3000);

import { Client } from '@modelcontextprotocol/client';
import { StreamableHTTPClientTransport } from '@modelcontextprotocol/client';
import { StdioClientTransport } from '@modelcontextprotocol/client';

// Remote server (Streamable HTTP)
const remoteClient = new Client({ name: 'my-client', version: '1.0.0' });
const httpTransport = new StreamableHTTPClientTransport(
  new URL('https://mcp.example.com/mcp')
);
await remoteClient.connect(httpTransport);

// Discover tools
const tools = await remoteClient.listTools();

// Call a tool
const result = await remoteClient.callTool({
  name: 'search_documents',
  arguments: { query: 'MCP protocol' }
});

// Local server (stdio)
const localClient = new Client({ name: 'local-client', version: '1.0.0' });
const stdioTransport = new StdioClientTransport({
  command: 'node',
  args: ['./build/index.js']
});
await localClient.connect(stdioTransport);
const localTools = await localClient.listTools();
